const i = $input.first() ? ($input.first().json || {}) : {};
function pick(){ for(var k=0;k<arguments.length;k++){ var v=arguments[k]; if(v!=null && String(v).trim()!=='') return String(v).trim(); } return ''; }
let custom = pick(i['Custom topic']); let drop = pick(i['Topic'], i.topic); if(/^custom/i.test(drop)) drop='';
let t = pick(custom, drop, i.query, i.text); t = t.replace(/^\/[a-zA-Z]+\b/, '').trim();
if(!t) t = ($env.DEFAULT_AWARENESS_TOPIC || 'phishing');
const fmt = pick(i['Format'], i.format).toLowerCase();
let format='Both'; if(fmt.indexOf('scorm')>=0 && fmt.indexOf('html')<0) format='SCORM'; else if(fmt.indexOf('html')>=0 && fmt.indexOf('scorm')<0) format='HTML';
const pm = parseInt(pick(i['Pass mark (%)'], i['Pass mark'], i.passMark),10);
const imgSel = pick(i['Section images'], i.illustrate);
let illustrate; if(imgSel) illustrate = !/^(no|false|off|0)/i.test(imgSel); else illustrate = (($env.ELEARNING_SECTION_IMAGES||'true').toString().toLowerCase()!=='false');
return [{ json: { topic:t, audience:(pick(i['Audience'],i.audience)||'All staff'), passMark:(isNaN(pm)?80:pm), format:format, illustrate:illustrate, date:new Date().toISOString().slice(0,10), client:($env.CLIENT_NAME||'').toString() } }];

