const d = $json.data || {};
const topic = $json.topic || 'Security Awareness';
const date = $json.date || new Date().toISOString().slice(0,10);
const client = ($json.client || '').toString();
const passMark = Number($json.passMark) || 80;
const format = $json.format || 'Both';
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
const title = d.title || (topic + ' — Awareness Module');
