const payload = { title:title, brand:brand, intro:(d.intro||''), sections:(d.sections||[]), questions:(d.questions||[]), passMark:passMark, images:(Array.isArray($json.images)?$json.images:[]) };
const dataJson = JSON.stringify(payload).replace(/</g,'\\u003c');

const CSS = "*{box-sizing:border-box} body{margin:0;font-family:-apple-system,'Segoe UI',Arial,sans-serif;color:#14202b;background:#eef2f6} .wrap{max-width:820px;margin:0 auto;background:#fff;min-height:100vh;box-shadow:0 0 40px rgba(0,0,0,.06)} .top{background:linear-gradient(135deg,#0E2233,#0E7C86);color:#fff;padding:22px 32px} .top .b{font-size:12px;letter-spacing:2px;text-transform:uppercase;color:#9fe4d8;font-weight:800} .top h1{margin:6px 0 0;font-size:24px} .prog{height:6px;background:#dde6ec} .prog span{display:block;height:6px;background:#0E7C86;transition:width .3s} .pane{padding:30px 34px;min-height:360px} h2{font-family:Georgia,serif;color:#0E2233;font-size:22px;margin:0 0 14px} p{font-size:15px;line-height:1.65;color:#2b3340} .kp{background:#F1F7F8;border-left:4px solid #0E7C86;border-radius:6px;padding:12px 16px;margin:14px 0} .kp li{font-size:14px;line-height:1.5;margin:5px 0} .q{margin:0 0 18px} .q .qt{font-weight:700;color:#0E2233;margin-bottom:8px} .opt{display:block;border:1px solid #dde6ec;border-radius:8px;padding:11px 14px;margin:7px 0;cursor:pointer;font-size:14px} .opt:hover{border-color:#0E7C86} .opt input{margin-right:10px} .nav{display:flex;justify-content:space-between;padding:18px 34px;border-top:1px solid #eef2f6} .btn{background:#0E7C86;color:#fff;border:0;border-radius:8px;padding:11px 22px;font-size:15px;font-weight:700;cursor:pointer} .btn.alt{background:#fff;color:#0E7C86;border:1px solid #0E7C86} .btn[disabled]{opacity:.4;cursor:default} .res{text-align:center;padding:40px} .res .big{font-size:54px;font-weight:800} .res .pass{color:#1E8E5A} .res .fail{color:#B02525} .pill{display:inline-block;padding:4px 12px;border-radius:14px;font-size:12px;font-weight:800;letter-spacing:.5px} .pill.pass{background:#E4F6EC;color:#1E8E5A} .pill.fail{background:#FDECEC;color:#B02525} .foot{padding:14px 34px;color:#8a98a4;font-size:11px;border-top:1px solid #eef2f6} .scene{width:100%;height:240px;border-radius:12px;margin:0 0 20px;background:#0E2233;background-size:cover;background-position:center;box-shadow:0 12px 28px rgba(14,34,51,.22)} .scene.ph{background:linear-gradient(135deg,#0E2233 0%,#0E7C86 100%)}";

const APP = "(function(){var data=DATA;var passMark=data.passMark||80;var total=(data.sections||[]).length;var app=document.getElementById('pane');var navEl=document.getElementById('nav');var prog=document.getElementById('progfill');var idx=-1;function esc(s){return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return {'&':'&amp;','<':'&lt;','>':'&gt;'}[c];});}function setProg(step){var pct=Math.round(((step+1)/(total+2))*100);prog.style.width=pct+'%';}function btn(label,fn,alt,disabled){var b=document.createElement('button');b.className='btn'+(alt?' alt':'');b.textContent=label;if(disabled)b.disabled=true;else b.onclick=fn;return b;}function nav(left,right){navEl.innerHTML='';navEl.appendChild(left||document.createElement('span'));navEl.appendChild(right||document.createElement('span'));}function intro(){idx=-1;setProg(-1);app.innerHTML='<h2>'+esc(data.title)+'</h2><p>'+esc(data.intro)+'</p><p style=\"color:#8a98a4;font-size:13px\">'+total+' short sections, then a quick knowledge check. Pass mark '+passMark+'%.</p>';nav(null,btn('Start \\u2192',function(){go(0);}));}function section(i){idx=i;setProg(i);var s=data.sections[i]||{};var body=(s.body||'').split(/\\n+/).map(function(p){return '<p>'+esc(p)+'</p>';}).join('');var kp=(s.keyPoints&&s.keyPoints.length)?('<div class=\"kp\"><b>Key points</b><ul>'+s.keyPoints.map(function(k){return '<li>'+esc(k)+'</li>';}).join('')+'</ul></div>'):'';var im=(data.images&&data.images[i])||'';var hero='<div class=\"scene'+(im?'':' ph')+'\"'+(im?(' style=\"background-image:url('+im+')\"'):'')+'></div>';app.innerHTML=hero+'<h2>'+esc(s.heading||('Section '+(i+1)))+'</h2>'+body+kp;nav(btn('\\u2190 Back',function(){go(i-1<0?-1:i-1);},true),btn(i+1<total?'Next \\u2192':'Knowledge check \\u2192',function(){go(i+1);}));}function quiz(){idx=total;setProg(total);var qs=data.questions||[];var html='<h2>Knowledge check</h2>';qs.forEach(function(q,qi){html+='<div class=\"q\"><div class=\"qt\">'+(qi+1)+'. '+esc(q.q)+'</div>';(q.options||[]).forEach(function(o,oi){html+='<label class=\"opt\"><input type=\"radio\" name=\"q'+qi+'\" value=\"'+oi+'\">'+esc(o)+'</label>';});html+='</div>';});app.innerHTML=html;nav(btn('\\u2190 Back',function(){go(total-1);},true),btn('Submit',grade));}function grade(){var qs=data.questions||[];var correct=0;qs.forEach(function(q,qi){var sel=document.querySelector('input[name=q'+qi+']:checked');if(sel&&Number(sel.value)===Number(q.answer))correct++;});var score=qs.length?Math.round((correct/qs.length)*100):0;var passed=score>=passMark;results(score,passed,correct,qs.length);scormReport(score,passed);}function results(score,passed,correct,n){idx=total+1;setProg(total+1);app.innerHTML='<div class=\"res\"><div class=\"big '+(passed?'pass':'fail')+'\">'+score+'%</div><div class=\"pill '+(passed?'pass':'fail')+'\">'+(passed?'PASSED':'NOT YET PASSED')+'</div><p>You answered '+correct+' of '+n+' correctly.</p></div>';nav(btn('Review answers',function(){review();},true),passed?null:btn('Try again',function(){quiz();}));}function review(){var qs=data.questions||[];var html='<h2>Answers</h2>';qs.forEach(function(q,qi){var ans=(q.options||[])[q.answer];html+='<div class=\"q\"><div class=\"qt\">'+(qi+1)+'. '+esc(q.q)+'</div><div class=\"kp\"><b>Correct:</b> '+esc(ans)+'<br><span style=\"font-size:13px;color:#5A6472\">'+esc(q.why||'')+'</span></div></div>';});app.innerHTML=html;nav(btn('\\u2190 Results',function(){go(total);},true),null);}function go(i){if(i<0)return intro();if(i<total)return section(i);if(i===total)return quiz();}function findAPI(win){var n=0;while(win&&win.API==null&&win.parent&&win.parent!=win&&n<12){win=win.parent;n++;}return (win&&win.API)||null;}var API=null;try{API=findAPI(window);if(!API&&window.top!==window)API=findAPI(window.top);}catch(e){}if(API){try{API.LMSInitialize('');API.LMSSetValue('cmi.core.lesson_status','incomplete');API.LMSCommit('');}catch(e){}}function scormReport(score,passed){if(!API)return;try{API.LMSSetValue('cmi.core.score.raw',String(score));API.LMSSetValue('cmi.core.score.min','0');API.LMSSetValue('cmi.core.score.max','100');API.LMSSetValue('cmi.core.lesson_status',passed?'passed':'failed');API.LMSCommit('');API.LMSFinish('');}catch(e){}}go(-1);})();";

